# exam-system upstream — 追加到 00-upstreams.conf
upstream exam-system {
    server exam-system-svc.exam-system.svc.cluster.local:18080;
}

server {
    listen 80;
    server_name xexam-system.yottastudios.com;
    return 301 https://$host$request_uri;
}

server {
    listen 443 ssl;
    server_name xexam-system.yottastudios.com;

    ssl_certificate /etc/ssl/yottastudios.com/cert.pem;
    ssl_certificate_key /etc/ssl/yottastudios.com/key.pem;

    client_max_body_size 100m;

    location / {
        proxy_pass http://exam-system;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # WebSocket support
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";

        proxy_connect_timeout 300;
        proxy_send_timeout 300;
        proxy_read_timeout 300;

        # CORS headers
        add_header Access-Control-Allow-Origin $http_origin always;
        add_header Access-Control-Allow-Methods "GET, POST, PUT, DELETE, OPTIONS" always;
        add_header Access-Control-Allow-Headers "Authorization, Content-Type, X-Requested-With" always;
        add_header Access-Control-Allow-Credentials true always;

        if ($request_method = 'OPTIONS') {
            return 204;
        }
    }
}

